class SeatManager {
public:
    SeatManager(int n) {
        available = vector<int>(n, 1);
    }

    int reserve() {
        if (available.empty()) return -1;
        int seatNumber = available.back();
        available.pop_back();
        return seatNumber;
    }

    void unreserve(int seatNumber) {
        available.push_back(seatNumber);
    }
private:
    vector<int> available;
};
```

